"""solution.py - TeamCollaborationManager implementation."""

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Dict, List, Optional


# ---------------------------------------------------------------------------
# Enums
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    TEAM_PERFORMANCE = "team_performance"
    PROJECT_PROGRESS = "project_progress"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    pass


class ValidationError(TeamCollaborationError):
    pass


class NotFoundError(TeamCollaborationError):
    pass


class AuthorizationError(TeamCollaborationError):
    pass


class DuplicateError(TeamCollaborationError):
    pass


class ConflictError(TeamCollaborationError):
    pass


# ---------------------------------------------------------------------------
# Models
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    assignee_id: Optional[int]
    status: TaskStatus
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime
    description: str = ""


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: List[Attachment]
    created_at: datetime
    edited_at: Optional[datetime]


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Sub-stores (each holds a reference to the shared lock)
# ---------------------------------------------------------------------------
class UserStore:
    def __init__(self, lock):
        self._lock = lock
        self._users: Dict[int, User] = {}
        self._by_username: Dict[str, int] = {}
        self._by_email: Dict[str, int] = {}


class ProjectStore:
    def __init__(self, lock):
        self._lock = lock
        self._projects: Dict[int, Project] = {}
        self._by_owner: Dict[int, List[int]] = {}


class TaskStore:
    def __init__(self, lock):
        self._lock = lock
        self._tasks: Dict[int, Task] = {}
        self._by_project: Dict[int, List[int]] = {}
        self._by_assignee: Dict[int, List[int]] = {}


class MessageStore:
    def __init__(self, lock):
        self._lock = lock
        self._messages: Dict[int, Message] = {}
        self._by_project: Dict[int, List[int]] = {}
        self._by_task: Dict[int, List[int]] = {}


class PerformanceStore:
    def __init__(self, lock):
        self._lock = lock
        self._ratings: Dict[int, Rating] = {}
        self._by_ratee: Dict[int, List[int]] = {}


class ReportStore:
    def __init__(self, lock):
        self._lock = lock


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    def __init__(self, now=None):
        self._now = now if now is not None else datetime.now
        self._lock = threading.RLock()
        self._id_counter = 0

        self.users = UserStore(self._lock)
        self.projects = ProjectStore(self._lock)
        self.tasks = TaskStore(self._lock)
        self.messages = MessageStore(self._lock)
        self.performance = PerformanceStore(self._lock)
        self.reports = ReportStore(self._lock)

    def _next_id(self) -> int:
        self._id_counter += 1
        return self._id_counter

    @staticmethod
    def _task_stats(tasks):
        """Return (total, completed, in_progress, not_started, completion_rate, avg_time).

        Aggregates counts and timing over a list of Task objects.
        Must be called while the shared lock is held.
        """
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
        not_started = total - completed - in_progress
        completion_rate = completed / total if total else 0.0
        times = [(t.completed_at - t.started_at).total_seconds()
                 for t in tasks
                 if t.status == TaskStatus.COMPLETED and t.started_at and t.completed_at]
        avg_time = sum(times) / len(times) if times else None
        return total, completed, in_progress, not_started, completion_rate, avg_time

    def _get_ratings(self, user_id):
        """Return (count, average, raw_list) for ratings received by user.

        Must be called while the shared lock is held.
        """
        rids = self.performance._by_ratee.get(user_id, [])
        ratings = [self.performance._ratings[rid] for rid in rids
                   if rid in self.performance._ratings]
        count = len(ratings)
        average = sum(r.score for r in ratings) / count if count else 0.0
        return count, average, ratings

    # -----------------------------------------------------------------------
    # Users
    # -----------------------------------------------------------------------

    def register_user(self, username: str, email: str, role=UserRole.MEMBER) -> User:
        with self._lock:
            username = username.strip()
            if not username:
                raise ValidationError("Username cannot be empty")
            if not email or "@" not in email:
                raise ValidationError("Invalid email")
            if not isinstance(role, UserRole):
                raise ValidationError("Invalid role")
            if username in self.users._by_username:
                raise DuplicateError("Username already exists")
            if email in self.users._by_email:
                raise DuplicateError("Email already exists")

            uid = self._next_id()
            user = User(id=uid, username=username, email=email,
                        role=role, created_at=self._now())
            self.users._users[uid] = user
            self.users._by_username[username] = uid
            self.users._by_email[email] = uid
            return copy.deepcopy(user)

    def get_user(self, user_id: int) -> User:
        with self._lock:
            if user_id not in self.users._users:
                raise NotFoundError("User not found")
            return copy.deepcopy(self.users._users[user_id])

    def list_users(self) -> list:
        with self._lock:
            return copy.deepcopy(
                sorted(self.users._users.values(), key=lambda u: u.id)
            )

    def update_user(self, user_id: int, username=None, email=None, role=None) -> User:
        with self._lock:
            if user_id not in self.users._users:
                raise NotFoundError("User not found")
            user = self.users._users[user_id]

            if username is not None:
                username = username.strip()
                if not username:
                    raise ValidationError("Username cannot be empty")
                if username != user.username and username in self.users._by_username:
                    raise DuplicateError("Username already exists")

            if email is not None:
                if not email or "@" not in email:
                    raise ValidationError("Invalid email")
                if email != user.email and email in self.users._by_email:
                    raise DuplicateError("Email already exists")

            if username is not None and username != user.username:
                del self.users._by_username[user.username]
                user.username = username
                self.users._by_username[username] = user_id

            if email is not None and email != user.email:
                del self.users._by_email[user.email]
                user.email = email
                self.users._by_email[email] = user_id

            if role is not None:
                user.role = role

            return copy.deepcopy(user)

    def delete_user(self, user_id: int):
        with self._lock:
            if user_id not in self.users._users:
                raise NotFoundError("User not found")
            if user_id in self.projects._by_owner and self.projects._by_owner[user_id]:
                raise ConflictError("User owns projects")
            if user_id in self.tasks._by_assignee:
                for tid in self.tasks._by_assignee[user_id]:
                    if tid not in self.tasks._tasks:
                        continue
                    if self.tasks._tasks[tid].status != TaskStatus.COMPLETED:
                        raise ConflictError("User has open tasks")

            user = self.users._users.pop(user_id)
            self.users._by_username.pop(user.username, None)
            self.users._by_email.pop(user.email, None)

    # -----------------------------------------------------------------------
    # Projects
    # -----------------------------------------------------------------------

    def create_project(self, name: str, start_date, end_date,
                       owner_id: int, description: str = "") -> Project:
        with self._lock:
            if owner_id not in self.users._users:
                raise NotFoundError("Owner not found")
            if not name or not name.strip():
                raise ValidationError("Project name cannot be empty")
            if end_date < start_date:
                raise ValidationError("end_date cannot be before start_date")

            pid = self._next_id()
            project = Project(id=pid, name=name, description=description,
                              start_date=start_date, end_date=end_date,
                              owner_id=owner_id)
            self.projects._projects[pid] = project
            self.projects._by_owner.setdefault(owner_id, []).append(pid)
            return copy.deepcopy(project)

    def get_project(self, project_id: int) -> Project:
        with self._lock:
            if project_id not in self.projects._projects:
                raise NotFoundError("Project not found")
            return copy.deepcopy(self.projects._projects[project_id])

    def list_projects(self) -> list:
        with self._lock:
            return copy.deepcopy(
                sorted(self.projects._projects.values(), key=lambda p: p.id)
            )

    def update_project(self, project_id: int, name=None, start_date=None,
                       end_date=None, description=None) -> Project:
        with self._lock:
            if project_id not in self.projects._projects:
                raise NotFoundError("Project not found")
            project = self.projects._projects[project_id]

            if name is not None and (not name or not name.strip()):
                raise ValidationError("Project name cannot be empty")

            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date cannot be before start_date")

            if name is not None:
                project.name = name
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description

            return copy.deepcopy(project)

    def delete_project(self, project_id: int):
        with self._lock:
            if project_id not in self.projects._projects:
                raise NotFoundError("Project not found")

            # Cascade: delete tasks and free assignee index
            task_ids = list(self.tasks._by_project.get(project_id, []))
            for tid in task_ids:
                task = self.tasks._tasks.pop(tid, None)
                if task and task.assignee_id is not None:
                    lst = self.tasks._by_assignee.get(task.assignee_id, [])
                    if tid in lst:
                        lst.remove(tid)
            self.tasks._by_project.pop(project_id, None)

            # Cascade: delete direct project messages
            for mid in list(self.messages._by_project.get(project_id, [])):
                self.messages._messages.pop(mid, None)
            self.messages._by_project.pop(project_id, None)

            # Cascade: delete task messages
            for tid in task_ids:
                for mid in list(self.messages._by_task.get(tid, [])):
                    self.messages._messages.pop(mid, None)
                self.messages._by_task.pop(tid, None)

            # Remove project and update owner index
            project = self.projects._projects.pop(project_id)
            owner_list = self.projects._by_owner.get(project.owner_id, [])
            if project_id in owner_list:
                owner_list.remove(project_id)

    # -----------------------------------------------------------------------
    # Tasks
    # -----------------------------------------------------------------------

    def create_task(self, project_id: int, title: str, assignee_id=None,
                    deadline=None, description: str = "") -> Task:
        with self._lock:
            if project_id not in self.projects._projects:
                raise NotFoundError("Project not found")
            if not title or not title.strip():
                raise ValidationError("Task title cannot be empty")
            if assignee_id is not None and assignee_id not in self.users._users:
                raise NotFoundError("Assignee not found")

            project = self.projects._projects[project_id]
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("Deadline before project start date")

            tid = self._next_id()
            task = Task(id=tid, project_id=project_id, title=title,
                        assignee_id=assignee_id, status=TaskStatus.NOT_STARTED,
                        deadline=deadline, started_at=None, completed_at=None,
                        created_at=self._now(), description=description)
            self.tasks._tasks[tid] = task
            self.tasks._by_project.setdefault(project_id, []).append(tid)
            if assignee_id is not None:
                self.tasks._by_assignee.setdefault(assignee_id, []).append(tid)
            return copy.deepcopy(task)

    def get_task(self, task_id: int) -> Task:
        with self._lock:
            if task_id not in self.tasks._tasks:
                raise NotFoundError("Task not found")
            return copy.deepcopy(self.tasks._tasks[task_id])

    def list_tasks_by_project(self, project_id: int) -> list:
        with self._lock:
            if project_id not in self.projects._projects:
                raise NotFoundError("Project not found")
            ids = self.tasks._by_project.get(project_id, [])
            return copy.deepcopy([self.tasks._tasks[tid]
                                   for tid in sorted(ids)
                                   if tid in self.tasks._tasks])

    def list_tasks_by_assignee(self, assignee_id: int) -> list:
        with self._lock:
            if assignee_id not in self.users._users:
                raise NotFoundError("User not found")
            ids = self.tasks._by_assignee.get(assignee_id, [])
            return copy.deepcopy([self.tasks._tasks[tid]
                                   for tid in sorted(ids)
                                   if tid in self.tasks._tasks])

    def _set_assignee(self, task, new_assignee_id):
        old = task.assignee_id
        if old is not None:
            lst = self.tasks._by_assignee.get(old, [])
            if task.id in lst:
                lst.remove(task.id)
        task.assignee_id = new_assignee_id
        if new_assignee_id is not None:
            self.tasks._by_assignee.setdefault(new_assignee_id, []).append(task.id)

    def assign_task(self, task_id: int, assignee_id: int) -> Task:
        with self._lock:
            if task_id not in self.tasks._tasks:
                raise NotFoundError("Task not found")
            if assignee_id not in self.users._users:
                raise NotFoundError("User not found")
            self._set_assignee(self.tasks._tasks[task_id], assignee_id)
            return copy.deepcopy(self.tasks._tasks[task_id])

    def reassign_task(self, task_id: int, new_assignee_id: int) -> Task:
        with self._lock:
            if task_id not in self.tasks._tasks:
                raise NotFoundError("Task not found")
            if new_assignee_id not in self.users._users:
                raise NotFoundError("User not found")
            self._set_assignee(self.tasks._tasks[task_id], new_assignee_id)
            return copy.deepcopy(self.tasks._tasks[task_id])

    def unassign_task(self, task_id: int) -> Task:
        with self._lock:
            if task_id not in self.tasks._tasks:
                raise NotFoundError("Task not found")
            self._set_assignee(self.tasks._tasks[task_id], None)
            return copy.deepcopy(self.tasks._tasks[task_id])

    def set_deadline(self, task_id: int, deadline) -> Task:
        with self._lock:
            if task_id not in self.tasks._tasks:
                raise NotFoundError("Task not found")
            task = self.tasks._tasks[task_id]
            if deadline is not None:
                project = self.projects._projects[task.project_id]
                if deadline < project.start_date:
                    raise ValidationError("Deadline before project start date")
            task.deadline = deadline
            return copy.deepcopy(task)

    def update_status(self, task_id: int, status) -> Task:
        with self._lock:
            if task_id not in self.tasks._tasks:
                raise NotFoundError("Task not found")
            if not isinstance(status, TaskStatus):
                raise ValidationError("Invalid status")
            task = self.tasks._tasks[task_id]
            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            else:  # NOT_STARTED
                task.started_at = None
                task.completed_at = None
            task.status = status
            return copy.deepcopy(task)

    # -----------------------------------------------------------------------
    # Messaging
    # -----------------------------------------------------------------------

    def post_message(self, author_id: int, body: str, project_id=None,
                     task_id=None, parent_id=None, attachments=None) -> Message:
        with self._lock:
            if author_id not in self.users._users:
                raise NotFoundError("Author not found")
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "Exactly one of project_id or task_id must be provided")
            if project_id is not None and project_id not in self.projects._projects:
                raise NotFoundError("Project not found")
            if task_id is not None and task_id not in self.tasks._tasks:
                raise NotFoundError("Task not found")
            has_attachments = bool(attachments)
            if not body and not has_attachments:
                raise ValidationError("Body cannot be empty without attachments")
            if parent_id is not None and parent_id not in self.messages._messages:
                raise NotFoundError("Parent message not found")

            now = self._now()
            att_list = []
            if attachments:
                for fname, data in attachments:
                    att_list.append(Attachment(filename=fname, size=len(data),
                                               uploaded_by=author_id, uploaded_at=now))

            mid = self._next_id()
            msg = Message(id=mid, author_id=author_id, body=body,
                          project_id=project_id, task_id=task_id,
                          parent_id=parent_id, attachments=att_list,
                          created_at=now, edited_at=None)
            self.messages._messages[mid] = msg
            if project_id is not None:
                self.messages._by_project.setdefault(project_id, []).append(mid)
            if task_id is not None:
                self.messages._by_task.setdefault(task_id, []).append(mid)
            return copy.deepcopy(msg)

    def edit_message(self, message_id: int, editor_id: int, new_body: str) -> Message:
        with self._lock:
            if message_id not in self.messages._messages:
                raise NotFoundError("Message not found")
            msg = self.messages._messages[message_id]
            if editor_id != msg.author_id:
                raise AuthorizationError("Only the author can edit")
            if not new_body and not msg.attachments:
                raise ValidationError("Body cannot be empty without attachments")
            msg.body = new_body
            msg.edited_at = self._now()
            return copy.deepcopy(msg)

    def add_attachment(self, message_id: int, uploader_id: int,
                       filename: str, data: bytes) -> Message:
        with self._lock:
            if message_id not in self.messages._messages:
                raise NotFoundError("Message not found")
            msg = self.messages._messages[message_id]
            if uploader_id != msg.author_id:
                raise AuthorizationError("Only the author can add attachments")
            if not filename:
                raise ValidationError("Filename cannot be empty")
            att = Attachment(filename=filename, size=len(data),
                             uploaded_by=uploader_id, uploaded_at=self._now())
            msg.attachments.append(att)
            return copy.deepcopy(msg)

    def list_messages_by_project(self, project_id: int) -> list:
        with self._lock:
            if project_id not in self.projects._projects:
                raise NotFoundError("Project not found")
            ids = self.messages._by_project.get(project_id, [])
            return copy.deepcopy([self.messages._messages[mid]
                                   for mid in sorted(ids)
                                   if mid in self.messages._messages])

    def list_messages_by_task(self, task_id: int) -> list:
        with self._lock:
            if task_id not in self.tasks._tasks:
                raise NotFoundError("Task not found")
            ids = self.messages._by_task.get(task_id, [])
            return copy.deepcopy([self.messages._messages[mid]
                                   for mid in sorted(ids)
                                   if mid in self.messages._messages])

    def delete_message(self, message_id: int, requester_id: int):
        with self._lock:
            if message_id not in self.messages._messages:
                raise NotFoundError("Message not found")
            msg = self.messages._messages[message_id]
            if requester_id != msg.author_id:
                raise AuthorizationError("Only the author can delete")
            del self.messages._messages[message_id]
            if msg.project_id is not None:
                lst = self.messages._by_project.get(msg.project_id, [])
                if message_id in lst:
                    lst.remove(message_id)
            if msg.task_id is not None:
                lst = self.messages._by_task.get(msg.task_id, [])
                if message_id in lst:
                    lst.remove(message_id)

    # -----------------------------------------------------------------------
    # Performance
    # -----------------------------------------------------------------------

    def get_completion_rate(self, user_id: int) -> float:
        with self._lock:
            if user_id not in self.users._users:
                raise NotFoundError("User not found")
            tasks = [self.tasks._tasks[tid]
                     for tid in self.tasks._by_assignee.get(user_id, [])
                     if tid in self.tasks._tasks]
            _, _, _, _, completion_rate, _ = self._task_stats(tasks)
            return completion_rate

    def get_average_completion_time(self, user_id: int):
        with self._lock:
            if user_id not in self.users._users:
                raise NotFoundError("User not found")
            tasks = [self.tasks._tasks[tid]
                     for tid in self.tasks._by_assignee.get(user_id, [])
                     if tid in self.tasks._tasks]
            *_, avg_time = self._task_stats(tasks)
            return avg_time

    def submit_rating(self, rater_id: int, ratee_id: int, score: int,
                      feedback: str = "", task_id=None) -> Rating:
        with self._lock:
            if rater_id not in self.users._users:
                raise NotFoundError("Rater not found")
            if ratee_id not in self.users._users:
                raise NotFoundError("Ratee not found")
            if rater_id == ratee_id:
                raise ConflictError("Cannot rate yourself")
            if not (1 <= score <= 5):
                raise ValidationError("Score must be 1-5")
            if task_id is not None and task_id not in self.tasks._tasks:
                raise NotFoundError("Task not found")

            rid = self._next_id()
            rating = Rating(id=rid, rater_id=rater_id, ratee_id=ratee_id,
                            score=score, feedback=feedback, task_id=task_id,
                            created_at=self._now())
            self.performance._ratings[rid] = rating
            self.performance._by_ratee.setdefault(ratee_id, []).append(rid)
            return copy.deepcopy(rating)

    def get_ratings_summary(self, user_id: int) -> dict:
        with self._lock:
            if user_id not in self.users._users:
                raise NotFoundError("User not found")
            count, average, ratings = self._get_ratings(user_id)
            return {"count": count, "average": average,
                    "ratings": copy.deepcopy(ratings)}

    def get_user_dashboard(self, user_id: int) -> dict:
        with self._lock:
            if user_id not in self.users._users:
                raise NotFoundError("User not found")
            tasks = [self.tasks._tasks[tid]
                     for tid in self.tasks._by_assignee.get(user_id, [])
                     if tid in self.tasks._tasks]
            total, completed, in_progress, not_started, completion_rate, avg_time = \
                self._task_stats(tasks)
            rc, ra, _ = self._get_ratings(user_id)
            return {
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_count": rc,
                "rating_average": ra,
            }

    # -----------------------------------------------------------------------
    # Reports
    # -----------------------------------------------------------------------

    def project_progress_report(self, project_id: int) -> dict:
        with self._lock:
            if project_id not in self.projects._projects:
                raise NotFoundError("Project not found")
            task_ids = self.tasks._by_project.get(project_id, [])
            tasks = [self.tasks._tasks[tid] for tid in task_ids
                     if tid in self.tasks._tasks]
            total = len(tasks)
            status_counts = {
                TaskStatus.NOT_STARTED.value: 0,
                TaskStatus.IN_PROGRESS.value: 0,
                TaskStatus.COMPLETED.value: 0,
            }
            for t in tasks:
                status_counts[t.status.value] += 1
            completed_n = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = completed_n / total if total else 0.0
            now = self._now()
            overdue = sum(1 for t in tasks
                          if t.deadline is not None
                          and t.deadline < now
                          and t.status != TaskStatus.COMPLETED)
            per_assignee: dict = {}
            for t in tasks:
                if t.assignee_id is None:
                    continue
                aid = t.assignee_id
                if aid not in per_assignee:
                    per_assignee[aid] = {
                        "total": 0,
                        TaskStatus.COMPLETED.value: 0,
                        TaskStatus.IN_PROGRESS.value: 0,
                        TaskStatus.NOT_STARTED.value: 0,
                    }
                per_assignee[aid]["total"] += 1
                per_assignee[aid][t.status.value] += 1
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None) -> dict:
        with self._lock:
            if project_id is not None and project_id not in self.projects._projects:
                raise NotFoundError("Project not found")
            if project_id is not None:
                scoped_ids = list(self.tasks._by_project.get(project_id, []))
            else:
                scoped_ids = list(self.tasks._tasks.keys())

            # Group tasks by assignee in one pass -- O(M) instead of O(N*M)
            tasks_by_assignee: Dict[int, list] = {}
            for tid in scoped_ids:
                if tid not in self.tasks._tasks:
                    continue
                t = self.tasks._tasks[tid]
                if t.assignee_id is not None:
                    tasks_by_assignee.setdefault(t.assignee_id, []).append(t)

            rows = []
            for uid in sorted(tasks_by_assignee):
                if uid not in self.users._users:
                    continue
                total, completed, in_progress, not_started, completion_rate, avg_time = \
                    self._task_stats(tasks_by_assignee[uid])
                rows.append({
                    "user_id": uid,
                    "total_tasks": total,
                    "completed_tasks": completed,
                    "in_progress_tasks": in_progress,
                    "not_started_tasks": not_started,
                    "completion_rate": completion_rate,
                    "average_completion_time": avg_time,
                })
            return {"report_type": ReportType.TEAM_PERFORMANCE.value, "rows": rows}

    def individual_performance_report(self, user_id: int) -> dict:
        with self._lock:
            if user_id not in self.users._users:
                raise NotFoundError("User not found")
            tasks = [self.tasks._tasks[tid]
                     for tid in self.tasks._by_assignee.get(user_id, [])
                     if tid in self.tasks._tasks]
            total, completed, in_progress, not_started, completion_rate, avg_time = \
                self._task_stats(tasks)
            rc, ra, _ = self._get_ratings(user_id)
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_count": rc,
                "rating_average": ra,
                "tasks": copy.deepcopy(tasks),
            }

    def export_report(self, report, fmt):
        with self._lock:
            if not isinstance(report, dict):
                raise ValidationError("report must be a dict")
            if not isinstance(fmt, ReportFormat):
                raise ValidationError("fmt must be a ReportFormat")
            if fmt == ReportFormat.CSV:
                return self._export_csv(report)
            return self._export_pdf(report)

    def _export_csv(self, report: dict) -> str:
        buf = io.StringIO()
        writer = csv.writer(buf)
        if "rows" in report:
            rows = report["rows"]
            header = list(rows[0].keys()) if rows else ["user_id"]
            writer.writerow(header)
            for row in rows:
                writer.writerow([str(row.get(k, "")) for k in header])
        else:
            writer.writerow(["field", "value"])
            for k, v in report.items():
                writer.writerow([str(k), str(v)])
        return buf.getvalue()

    def _export_pdf(self, report: dict) -> bytes:
        lines = [b"%PDF-1.4"]
        for k, v in report.items():
            entry = "% {0}: {1}".format(k, str(v))[:120]
            lines.append(entry.encode("ascii", errors="replace"))
        lines.append(b"%%EOF")
        return b"\n".join(lines)
